syntax = "proto3";
package counter;

import "gogoproto/gogo.proto";

option go_package = "github.com/yourusername/myapp/x/counter/types";

// Msg defines the Msg service.
service Msg {
  // Increment increments the counter for an address.
  rpc Increment(MsgIncrement) returns (MsgIncrementResponse);
  // Reset resets the counter for an address.
  rpc Reset(MsgReset) returns (MsgResetResponse);
}

// MsgIncrement represents a message to increment a counter.
message MsgIncrement {
  string creator = 1;
}

// MsgIncrementResponse is the response type for the Increment message.
message MsgIncrementResponse {}

// MsgReset represents a message to reset a counter.
message MsgReset {
  string creator = 1;
}

// MsgResetResponse is the response type for the Reset message.
message MsgResetResponse {}

// GenesisState defines the state that must be provided at genesis.
message GenesisState {
  repeated Counter counters = 1 [(gogoproto.nullable) = false];
}

// Counter represents a counter with an address and value.
message Counter {
  string address = 1;
  uint64 count = 2;
}
