### 3. `x/counter/types/msg_server.go`

Implement the MsgServer.

```go
package types

import (
	"context"
	sdk "github.com/cosmos/cosmos-sdk/types"
	sdkerrors "github.com/cosmos/cosmos-sdk/types/errors"
)

type msgServer struct {
	Keeper Keeper
}

// NewMsgServerImpl returns an implementation of the MsgServer interface.
func NewMsgServerImpl(keeper Keeper) MsgServer {
	return &msgServer{Keeper: keeper}
}

var _ MsgServer = msgServer{}

func (k msgServer) Increment(goCtx context.Context, msg *MsgIncrement) (*MsgIncrementResponse, error) {
	ctx := sdk.UnwrapSDKContext(goCtx)
	address, err := sdk.AccAddressFromBech32(msg.Creator)
	if err != nil {
		return nil, sdkerrors.Wrapf(sdkerrors.ErrInvalidAddress, "invalid address (%s)", err)
	}

	count, err := k.Keeper.Counters.Get(ctx, address)
	if err != nil && !k.Keeper.Counters.Has(ctx, address) {
		count = 0
	}
	count++

	k.Keeper.Counters.Set(ctx, address, count)

	return &MsgIncrementResponse{}, nil
}

func (k msgServer) Reset(goCtx context.Context, msg *MsgReset) (*MsgResetResponse, error) {
	ctx := sdk.UnwrapSDKContext(goCtx)
	address, err := sdk.AccAddressFromBech32(msg.Creator)
	if err != nil {
		return nil, sdkerrors.Wrapf(sdkerrors.ErrInvalidAddress, "invalid address (%s)", err)
	}

	k.Keeper.Counters.Set(ctx, address, 0)

	return &MsgResetResponse{}, nil
}
```

