```go
package main

import (
	"crypto/ed25519"
	"crypto/rand"
	"encoding/base64"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"io/ioutil"
	"net/http"
	"strings"

	"golang.org/x/crypto/pem"
)

const (
	maxMessageSize = 1024 // Maximum message size in bytes
	privateKeyFile = "private_key.pem" // Path to the PEM file containing the private key
)

type Request struct {
	Message string `json:"message"`
}

type Response struct {
	Signature string `json:"signature"`
	Pubkey    string `json:"pubkey"`
}

var privateKey ed25519.PrivateKey

func main() {
	var err error
	privateKey, err = loadEd25519PrivateKey(privateKeyFile)
	if err != nil {
		fmt.Printf("Failed to load private key: %v\n", err)
		return
	}

	http.HandleFunc("/sign", signHandler)

	fmt.Println("Starting server at :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server failed to start: %v\n", err)
	}
}

func loadEd25519PrivateKey(pemFile string) (ed25519.PrivateKey, error) {
	data, err := ioutil.ReadFile(pemFile)
	if err != nil {
		return nil, fmt.Errorf("failed to read PEM file: %w", err)
	}

	block, _ := pem.Decode(data)
	if block == nil || block.Type != "PRIVATE KEY" {
		return nil, errors.New("failed to decode PEM block containing the private key")
	}

	privateKey, err := ed25519.ParsePrivateKey(block.Bytes)
	if err != nil {
		return nil, fmt.Errorf("failed to parse Ed25519 private key: %w", err)
	}

	return privateKey, nil
}

func signHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Only POST method is allowed", http.StatusMethodNotAllowed)
		return
	}

	body, err := ioutil.ReadAll(r.Body)
	if err != nil || len(body) > maxMessageSize {
		http.Error(w, "Invalid request body or size exceeds limit", http.StatusBadRequest)
		return
	}
	defer r.Body.Close()

	var req Request
	if err := json.Unmarshal(body, &req); err != nil || req.Message == "" {
		http.Error(w, "Invalid JSON format or empty message", http.StatusBadRequest)
		return
	}

	publicKey := privateKey.Public().(ed25519.PublicKey)

	signature := ed25519.Sign(privateKey, []byte(req.Message))

	resp := Response{
		Signature: hex.EncodeToString(signature),
		Pubkey:    hex.EncodeToString(publicKey),
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(resp)
}
```

### Explanation:

- **Loading the Private Key**: The `loadEd25519PrivateKey` function reads a PEM file and decodes it to extract the Ed25519 private key.

- **HTTP Handler (`signHandler`)**:
  - Validates that only POST requests are accepted.
  - Reads and limits the size of the request body.
  - Parses the JSON body into a `Request` struct, ensuring the message is non-empty.
  - Generates an Ed25519 signature for the message using the loaded private key.
  - Returns a JSON response containing the hexadecimal-encoded signature and public key.

- **Main Function**:
  - Loads the private key from a PEM file on startup.
  - Registers the `signHandler` function to handle requests at the `/sign` endpoint.
  - Starts an HTTP server listening on port `8080`.

### Notes:

- Ensure you have a valid Ed25519 private key in PEM format saved as `private_key.pem` in the same directory as your Go program or adjust the path accordingly.

- The maximum message size is set to 1024 bytes. You can modify this value based on your requirements.

- The program uses hexadecimal encoding for both the signature and public key in the response JSON. If you prefer base64, replace `hex.EncodeToString` with `base64.StdEncoding.EncodeToString`.

